/**
 * Email notification handler — formats and dispatches email notifications
 * for order status changes.
 *
 * Integrates with the EventBus pattern: subscribes to order events and
 * dispatches formatted emails. Uses UserRepository to resolve user email
 * addresses from order data.
 *
 * Depends on:
 * - EventBus (event system) for receiving order events
 * - UserRepository (data layer) for resolving user emails
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderStatusChangedEvent, OrderCreatedEvent } from '../events/event-types.js';
import type { UserRepository } from '../repositories/user.repository.js';
import type { OrderStatus } from '../models/order.js';
import { Logger } from '../utils/logger.js';

export interface EmailMessage {
  to: string;
  subject: string;
  htmlBody: string;
  textBody: string;
  sentAt: Date;
}

const STATUS_LABELS: Record<OrderStatus, string> = {
  pending: 'Pending',
  confirmed: 'Confirmed',
  shipped: 'Shipped',
  delivered: 'Delivered',
  cancelled: 'Cancelled',
};

const STATUS_MESSAGES: Record<OrderStatus, string> = {
  pending: 'Your order has been received and is awaiting confirmation.',
  confirmed: 'Your order has been confirmed and is being prepared.',
  shipped: 'Your order has been shipped and is on its way.',
  delivered: 'Your order has been delivered. Thank you for your purchase!',
  cancelled: 'Your order has been cancelled. If this was unexpected, please contact support.',
};

export class EmailNotificationHandler {
  private logger = new Logger('EmailNotificationHandler');
  private sentEmails: EmailMessage[] = [];

  constructor(
    private eventBus: EventBus,
    private userRepository: UserRepository,
  ) {
    this.registerHandlers();
  }

  private registerHandlers(): void {
    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });

    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });
  }

  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    const user = this.userRepository.findById(event.order.userId);
    if (!user) {
      this.logger.warn(`Cannot send email: user not found for order ${event.order.id}`);
      return;
    }

    const newStatusLabel = STATUS_LABELS[event.newStatus as OrderStatus] ?? event.newStatus;
    const statusMessage = STATUS_MESSAGES[event.newStatus as OrderStatus] ?? `Your order status has changed to ${event.newStatus}.`;

    const subject = `Order ${event.order.id} — ${newStatusLabel}`;

    const textBody = [
      `Hi ${user.name},`,
      '',
      statusMessage,
      '',
      `Order: ${event.order.id}`,
      `Status: ${event.previousStatus} → ${event.newStatus}`,
      '',
      'Thank you for shopping with us.',
    ].join('\n');

    const htmlBody = [
      `<h2>Order Status Update</h2>`,
      `<p>Hi ${user.name},</p>`,
      `<p>${statusMessage}</p>`,
      `<table>`,
      `<tr><td><strong>Order</strong></td><td>${event.order.id}</td></tr>`,
      `<tr><td><strong>Previous Status</strong></td><td>${event.previousStatus}</td></tr>`,
      `<tr><td><strong>New Status</strong></td><td>${event.newStatus}</td></tr>`,
      `</table>`,
      `<p>Thank you for shopping with us.</p>`,
    ].join('\n');

    this.sendEmail({ to: user.email, subject, htmlBody, textBody });
  }

  private handleOrderCreated(event: OrderCreatedEvent): void {
    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity} — $${(item.unitPrice * item.quantity).toFixed(2)}`)
      .join('\n');

    const subject = `Order Confirmation — ${event.order.id}`;

    const textBody = [
      `Hi ${event.user.name},`,
      '',
      'Thank you for your order! Here is your confirmation:',
      '',
      itemSummary,
      '',
      `Total: $${event.order.total.toFixed(2)}`,
      '',
      'We will notify you when your order status changes.',
    ].join('\n');

    const htmlBody = [
      `<h2>Order Confirmation</h2>`,
      `<p>Hi ${event.user.name},</p>`,
      `<p>Thank you for your order! Here is your confirmation:</p>`,
      `<table>`,
      ...event.order.items.map(
        (item) =>
          `<tr><td>${item.name}</td><td>x${item.quantity}</td><td>$${(item.unitPrice * item.quantity).toFixed(2)}</td></tr>`,
      ),
      `<tr><td><strong>Total</strong></td><td></td><td><strong>$${event.order.total.toFixed(2)}</strong></td></tr>`,
      `</table>`,
      `<p>We will notify you when your order status changes.</p>`,
    ].join('\n');

    this.sendEmail({ to: event.user.email, subject, htmlBody, textBody });
  }

  private sendEmail(params: Omit<EmailMessage, 'sentAt'>): void {
    const email: EmailMessage = {
      ...params,
      sentAt: new Date(),
    };
    this.sentEmails.push(email);
    this.logger.info(`Email sent to ${params.to}: ${params.subject}`);
  }

  /**
   * Get all sent emails.
   */
  getSentEmails(): EmailMessage[] {
    return [...this.sentEmails];
  }

  /**
   * Get emails sent to a specific address.
   */
  getEmailsFor(email: string): EmailMessage[] {
    return this.sentEmails.filter((e) => e.to === email);
  }

  /**
   * Get the count of sent emails.
   */
  getSentEmailCount(): number {
    return this.sentEmails.length;
  }

  /**
   * Clear all sent emails (useful for testing).
   */
  clearEmails(): void {
    this.sentEmails = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { EmailNotificationHandler } from '../../src/notifications/email-handler.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { Database } from '../../src/utils/database.js';
import type { OrderStatusChangedEvent, OrderCreatedEvent } from '../../src/events/event-types.js';

describe('EmailNotificationHandler', () => {
  let eventBus: EventBus;
  let db: Database;
  let userRepository: UserRepository;
  let handler: EmailNotificationHandler;

  const testUser = {
    id: 'user-1',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member' as const,
    createdAt: new Date(),
    updatedAt: new Date(),
  };

  beforeEach(() => {
    eventBus = new EventBus();
    db = new Database();
    userRepository = new UserRepository(db);
    userRepository.save(testUser);
    handler = new EmailNotificationHandler(eventBus, userRepository);
  });

  describe('order:status-changed emails', () => {
    it('should send an email when order status changes', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('alice@example.com');
      expect(emails[0]?.subject).toContain('order-1');
      expect(emails[0]?.subject).toContain('Confirmed');
    });

    it('should include status transition in text body', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = handler.getSentEmails();
      expect(emails[0]?.textBody).toContain('confirmed');
      expect(emails[0]?.textBody).toContain('shipped');
      expect(emails[0]?.textBody).toContain('Hi Alice');
    });

    it('should include HTML body with status details', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'delivered',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'shipped',
        newStatus: 'delivered',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = handler.getSentEmails();
      expect(emails[0]?.htmlBody).toContain('<h2>Order Status Update</h2>');
      expect(emails[0]?.htmlBody).toContain('delivered');
      expect(emails[0]?.htmlBody).toContain('shipped');
    });

    it('should use status-specific messages', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'cancelled',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'cancelled',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = handler.getSentEmails();
      expect(emails[0]?.textBody).toContain('cancelled');
      expect(emails[0]?.textBody).toContain('contact support');
    });

    it('should not send email if user not found', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'unknown-user',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(handler.getSentEmails()).toHaveLength(0);
    });

    it('should send emails for each status change', async () => {
      const makeEvent = (
        previousStatus: string,
        newStatus: string,
        status: string,
      ): OrderStatusChangedEvent => ({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: status as any,
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus,
        newStatus,
        timestamp: new Date(),
      });

      await eventBus.emit(makeEvent('pending', 'confirmed', 'confirmed'));
      await eventBus.emit(makeEvent('confirmed', 'shipped', 'shipped'));
      await eventBus.emit(makeEvent('shipped', 'delivered', 'delivered'));

      expect(handler.getSentEmails()).toHaveLength(3);
      expect(handler.getSentEmails()[0]?.subject).toContain('Confirmed');
      expect(handler.getSentEmails()[1]?.subject).toContain('Shipped');
      expect(handler.getSentEmails()[2]?.subject).toContain('Delivered');
    });
  });

  describe('order:created emails', () => {
    it('should send confirmation email on order creation', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: testUser,
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('alice@example.com');
      expect(emails[0]?.subject).toContain('Order Confirmation');
      expect(emails[0]?.textBody).toContain('Widget x2');
      expect(emails[0]?.textBody).toContain('$20.00');
    });

    it('should include item details in HTML body', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
            { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
          ],
          total: 45,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: testUser,
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = handler.getSentEmails();
      expect(emails[0]?.htmlBody).toContain('Widget');
      expect(emails[0]?.htmlBody).toContain('Gadget');
      expect(emails[0]?.htmlBody).toContain('$45.00');
    });
  });

  describe('email management', () => {
    it('should filter emails by address', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: testUser,
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(handler.getEmailsFor('alice@example.com')).toHaveLength(1);
      expect(handler.getEmailsFor('bob@example.com')).toHaveLength(0);
    });

    it('should count sent emails', async () => {
      expect(handler.getSentEmailCount()).toBe(0);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(handler.getSentEmailCount()).toBe(1);
    });

    it('should clear emails', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      handler.clearEmails();
      expect(handler.getSentEmailCount()).toBe(0);
    });
  });
});

